// Get all rows
const loans = items.map(item => item.json);

// 1️⃣ Total Active Loans
const totalActiveLoans = loans.length;


// 2️⃣ Percentage of Bad Loans
const badLoans = loans.filter(loan => 
    loan.loan_condition !== "GOOD LOAN"
);

const badLoanPercentage = totalActiveLoans > 0
    ? ((badLoans.length / totalActiveLoans) * 100).toFixed(2)
    : 0;


// 3️⃣ Highest Interest Rate
const highestInterestRate = Math.max(
    ...loans.map(loan => parseFloat(loan.interest_rate))
).toFixed(2);


// 4️⃣ Average Interest Rate by Grade
let gradeInterestMap = {};

loans.forEach(loan => {
    const grade = loan.grade;
    const rate = parseFloat(loan.interest_rate);

    if (!gradeInterestMap[grade]) {
        gradeInterestMap[grade] = [];
    }

    gradeInterestMap[grade].push(rate);
});

let avgInterestByGrade = {};

for (let grade in gradeInterestMap) {
    const rates = gradeInterestMap[grade];
    const avg = rates.reduce((a, b) => a + b, 0) / rates.length;
    avgInterestByGrade[grade] = avg.toFixed(2);
}


// 5️⃣ Regional Default Rate
let regionStats = {};

loans.forEach(loan => {
    const region = loan.region;

    if (!regionStats[region]) {
        regionStats[region] = { total: 0, bad: 0 };
    }

    regionStats[region].total++;

    if (loan.loan_condition !== "GOOD LOAN") {
        regionStats[region].bad++;
    }
});

let regionalDefaultRate = {};

for (let region in regionStats) {
    const { total, bad } = regionStats[region];
    const percent = total > 0 ? (bad / total) * 100 : 0;
    regionalDefaultRate[region] = percent.toFixed(2);
}


// Final Output
return [
  {
    json: {
      totalActiveLoans,
      badLoanPercentage: badLoanPercentage + "%",
      highestInterestRate: highestInterestRate + "%",
      avgInterestByGrade,
      regionalDefaultRate
    }
  }
];

